/**
 * RRROCA Smart Search — Fuse.js fuzzy search
 * Searches all site content client-side.
 * Search index is generated by Hugo at build time.
 */

(function() {
  'use strict';

  let searchIndex = null;
  let fuse = null;

  function escapeHTML(str) {
    return String(str ?? '')
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#39;');
  }

  function getSafePermalink(value) {
    return typeof value === 'string' && /^\/(?!\/)/.test(value)
      ? escapeHTML(value)
      : '#';
  }

  // Load self-hosted Fuse.js so search remains available without CDN dependencies.
  function loadFuse() {
    return new Promise((resolve, reject) => {
      if (window.Fuse) { resolve(); return; }
      const script = document.createElement('script');
      script.src = '/js/vendor/fuse.min.js';
      script.onload = resolve;
      script.onerror = reject;
      document.head.appendChild(script);
    });
  }

  function getBaseUrl() {
    if (window.RRROCA && typeof window.RRROCA.getBaseUrl === 'function') {
      return window.RRROCA.getBaseUrl();
    }

    const meta = document.querySelector('meta[name="base-url"]');
    const content = meta && meta.content ? meta.content.trim() : '';
    return content ? content.replace(/\/$/, '') : '';
  }

  // Load search index (generated by Hugo)
  async function loadIndex() {
    if (searchIndex) return;
    try {
      const base = getBaseUrl();
      const resp = await fetch(base + '/index.json');
      searchIndex = await resp.json();
      await loadFuse();
      fuse = new Fuse(searchIndex, {
        keys: [
          { name: 'title', weight: 0.4 },
          { name: 'content', weight: 0.3 },
          { name: 'section', weight: 0.15 },
          { name: 'tags', weight: 0.15 }
        ],
        threshold: 0.3,
        includeScore: true,
        includeMatches: true,
        minMatchCharLength: 2,
        limit: 10
      });
    } catch (e) {
      console.warn('Search index not available:', e);
    }
  }

  function openSearch() {
    const overlay = document.getElementById('search-overlay');
    if (!overlay) return;
    overlay.classList.add('open');
    document.getElementById('search-input').focus();
    loadIndex();
    document.body.style.overflow = 'hidden';
  }

  function closeSearch() {
    const overlay = document.getElementById('search-overlay');
    if (!overlay) return;
    overlay.classList.remove('open');
    document.body.style.overflow = '';
  }

  window.openSearch = openSearch;
  window.closeSearch = closeSearch;

  // Search handler
  function handleSearch(e) {
    const query = e.target.value.trim();
    const results = document.getElementById('search-results');
    if (!results) return;

    if (!query || query.length < 2) {
      results.innerHTML = '<p class="search-hint">Start typing to search across all community content...</p>';
      return;
    }

    if (!fuse) {
      results.innerHTML = '<p class="search-hint">Loading search index...</p>';
      return;
    }

    const matches = fuse.search(query);
    if (matches.length === 0) {
      results.innerHTML = `<p class="search-hint">No results for "<strong>${escapeHTML(query)}</strong>". Try different keywords.</p>`;
      return;
    }

    results.innerHTML = matches.map(m => {
      const section = escapeHTML(m.item.section || 'Page');
      const title = escapeHTML(m.item.title || 'Untitled');
      const preview = escapeHTML((m.item.content || '').substring(0, 150));
      const permalink = getSafePermalink(m.item.permalink);

      return `
      <a href="${permalink}" class="search-result">
        <span class="search-result-section">${section}</span>
        <strong>${title}</strong>
        <p>${preview}...</p>
      </a>
    `;
    }).join('');
  }

  // Bind events
  document.addEventListener('DOMContentLoaded', () => {
    const input = document.getElementById('search-input');
    if (input) {
      input.addEventListener('input', handleSearch);
    }

    document.querySelectorAll('.search-close').forEach((button) => {
      button.addEventListener('click', closeSearch);
    });
  });

  // Keyboard shortcuts
  document.addEventListener('keydown', (e) => {
    // Ctrl+K or Cmd+K to open search
    if ((e.ctrlKey || e.metaKey) && e.key === 'k') {
      e.preventDefault();
      openSearch();
    }
    // Escape to close search
    if (e.key === 'Escape') {
      closeSearch();
    }
  });
})();
